module morphological_dilation(  
    input [8:0] binary_matrix,  // 3x3 binary matrix flattened to a 9-bit input  
    output reg dilated_value    // Output of the dilation operation  
);  
    always @(*) begin  
        // Perform dilation: check if there is at least one '1' in the 3x3 region  
        if (binary_matrix[0] | binary_matrix[1] | binary_matrix[2] |  
            binary_matrix[3] | binary_matrix[4] | binary_matrix[5] |  
            binary_matrix[6] | binary_matrix[7] | binary_matrix[8])  
            dilated_value = 1'b1;  
        else  
            dilated_value = 1'b0;  
    end  
endmodule
